INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775041667959', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Dibawah ini yang bukan merupakan kelompok utama dari molekul organik yang dibutuhkan makhluk hidup adalah...', 'Karbohidrat', 'Lemak', 'Protein', 'Asam asetat', NULL, 'D', 'Empat kelompok utama molekul organik (biomolekul) yang dibutuhkan makhluk hidup untuk struktur, energi, dan fungsi seluler adalah karbohidrat, protein, lipid (lemak) dan asam nukleat.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:07:47.959000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
