INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775041848019', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Kumpulan berbagai jenis individu di suatu daerah tertentu disebut...', 'Bioma', 'Biosfer', 'Populasi', 'Komunitas', NULL, 'C', 'Populasi adalah keseluruhan kumpulan elemen, individu,atau subjek yang memiliki karakteristik serupa.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:10:48.019000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775041941576', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Cabang biologi yang mempelajari tentang struktur tubuh bagian dalam dari makhluk hidup disebut...', 'Morfologi', 'Anatomi', 'Fisiologi', 'Taksonomi', NULL, 'B', 'Anatomi adalah cabang ilmu biologi yang mempelajari tentang struktur tubuh makhluk hidup, terutama susunan,bentuk, dan hubungan antar organ.', 'Mudah', 4, 'DISETUJUI', '2026-04-01T19:12:21.576000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775042097042', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Aktivitas manusia dibawah ini dapat menurunkan keanekaragaman hayati, kecuali...', 'Perusakan habitat', 'Penggunaan pestisida', 'Kultur jaringan', 'Pertanian monokultur', NULL, 'C', 'Kultur jaringan adalah teknik perbanyakan vegetatif tanaman dengan mengisolasi bagian tanaman (sel,jaringan,atau organ) dan menumbuhkannya dalam media steril bernutrisi.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:14:57.042000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775042184553', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Faktor yang menyebabkan individu dalam satu spesies berbeda satu sama lain adalah...', 'Lingkungan', 'Jenis makanan', 'Komposisi gen dalam kromosom', 'Aktivitas yang dilakukan', NULL, 'C', 'Komposisi gen dalam kromosom merupakan penyebab utama perbedaan (variasi) antar individu dalam satu spesies.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:16:24.553000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775042279443', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Perbedaan yang ditemukan diantara jenis mangga harum manis, mangga madu, mangga golek dan mangga gadung menunjukkan adanya...', 'Adaptasi', 'Identifikasi', 'Evolusi', 'Variasi', NULL, 'D', 'Variasi genetik adalah perbedaan urutan DNA antar individu dalam satu spesies atau populasi,yang menyebabkan keragaman sifat seperti warna mata atau golongan darah. Contoh pada tumbuhan yaitu perbedaan warna mawar (merah,putih,kuning).', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:17:59.443000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775042377730', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Zat hijau pada daun yang berguna untuk melangsungkan proses fotosintesis untuk memenuhi kebutuhan makanan pada tumbuhan disebut...', 'Klorofil', 'Talus', 'Selulosa', 'Sitoplasma', NULL, 'A', 'Klorofil adalah pigmen hijau alami pada tumbuhan yang berfungsi menyerap energi matahari untuk fotosintesis.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:19:37.730000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775042506340', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Kumpulan sel muda yang selalu melaksanakan pembelahan atau bersifat embrional adalah pengertian dari jaringan...', 'Epidermis', 'Parenkim', 'Sklerenkim', 'Meristem', NULL, 'D', 'Jaringan meristem adalah jaringan muda pada tumbuhan yang sel-selnya aktif membelah secara motosis, bersifat embrional,dan belum mengalami diferensiasi.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:21:46.340000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775042574430', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Jaringan yang membawa hasil fotosintesis dari daun ke seluruh tubuh tumbuhan disebut...', 'Xilem', 'Floem', 'Kambium', 'Korteks', NULL, 'B', 'Floem adalah jaringan pengangkut pada tumbuhan yang berfungsi untuk mentranslokasikan hasil fotosintesis dari daun ke seluruh bagian tumbuhan yang membutuhkan seperti batang,akar,bunga dan buah.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:22:54.431000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775042653128', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Organ pokok pada tumbuhan adalah...', 'Akar, batang, bunga', 'Akar dan batang', 'Batang, daun, bunga', 'Akar, batang, daun', NULL, 'D', 'Organ pokok pada tumbuhan terdiri dari tiga bagian utama, yaitu akar (radix),batang (caulis),dan daun (folium).', 'Mudah', 4, 'DISETUJUI', '2026-04-01T19:24:13.128000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775042799848', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Sel darah yang mengandung hemoglobin yang berfungsi untuk mengikat oksigen adalah...', 'Leukosit', 'Eritrosit', 'Trombosit', 'Plasma darah', NULL, 'B', 'Eritrosit (sel darah merah) adalah komponen darah terbanyak yang mengandung hemoglobin untuk mengikat oksigen dari paru-paru ke seluruh tubuh.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:26:39.848000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775042869324', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Organ yang berperan dalam struktur penyerapan zat makanan adalah...', 'Paru-paru', 'Hati', 'Usus', 'Lambung', NULL, 'C', 'Organ utama yang berperan dalam struktur penyerapan zat (nutrisi) pada manusia adalah usus.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:27:49.324000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775042976613', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Enzim yang terdapat di mulut yang memecah amilum menjadi maltosa pada pencernaan kimiawi disebut...', 'Pepsin', 'Ptialin', 'Tripsin', 'Sukrase', NULL, 'B', 'Enzim ptialin (amilase Saliva) adalah enzim pencernaan di air liur yang diproduksi kelenjar ludah Untu memecah karbohidrat/Pati menjadi gula sederhana (maltosa) di mulut.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:29:36.613000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775043249542', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Berikut ini urutan proses pencernaan yang benar adalah...', 'Rongga mulut - faring - lambung - usus halus - usus besar - anus', 'Rongga mulut - esofagus - lambung - usus besar - usus halus - rektum - anus', 'Rongga mulut - esofagus - lambung - usus halus - usus besar - rektum - anus', 'Rongga mulut - laring - lambung - usus besar - usus halus - rektum - anus', NULL, 'C', 'Urutan sistem pencernaan manusia dimulai dari mulut,Kerongkongan (esofagus), lambung, usus halus, usus besar, rektum, dan berakhir di anus.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:34:09.542000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775043343676', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Alat penyaring pada ginjal sebagai struktur pendukung pembuangan sisa metabolisme disebut...', 'Augmentasi', 'Pelvis', 'Korteks', 'Nefron', NULL, 'D', 'Nefron adalah unit fungsional terkecil ginjal yang menyaring darah untuk menghasilkan urine, mengatur cairan,elektrolit,dan tekanan darah.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:35:43.676000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775043565002', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Air susu ibu yang diproduksi di awal pasca persalinan disebut colostrum, yang banyak mengandung antibodi dari ibu merupakan sistem pertahanan pada tubuh yang termasuk...', 'Imunitas aktif alami', 'Imunitas aktif buatan', 'Imunitas pasif alami', 'Imunitas pasif buatan', NULL, 'C', 'Air susu ibu (ASI) adalah bentuk imunitas pasif alami. Kolostrum pada ASI memberikan antibodi dari ibu ke bayi secara alami.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:39:25.002000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775043675929', 'MPL_1774681038018', 'KLS_1774678349870', 'sarah001', 'Salah satu bentuk dakwah dengan menunjukkan keramahan islam adalah...', 'Memaksa orang lain mengikuti ajaran islam', 'Bersikap kasar kepada yang berbeda pendapat', 'Menunjukkan akhlak mulia dalam kehidupan sehari-hari', 'Menghindari interaksi dengan masyarakat', NULL, 'C', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:41:15.929000', NULL, NULL, 'PKT_1775043675758', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775043711465', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Munculnya respon imun berlebih terhadap zat atau kondisi tertentu yang dapat menimbulkan gejala seperti pilek, ruam kulit, gatal, atau bahkan sesak napas merupakan ciri kelainan pada sistem kekebalan tubuh yang disebut dengan...', 'Autoimun', 'Alergi', 'HIV', 'Lupus', NULL, 'B', 'Tanda-tanda alergi umumnya melibatkan reaksi pada kulit (gatal,ruam,biduran), pernapasan (bersin,hidung tersumbat,batuk,sesak),mata (merah, berair), dan pencernaan (mual,diare) yang muncul setelah terpapar alergen.', 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:41:51.465000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775044485378', 'MPL_1774681038018', 'KLS_1774678349870', 'sarah001', 'Tujuan utama mendakwahkan islam dengan cara ramah adalah...', 'Agar ditakuti oleh orang lain', 'Supaya orang lain tertarik dan memahami ajaran islam dengan baik', 'Untuk menunjukkan kehebatan diri', 'Agar mendapat pujian dari masyarakat', NULL, 'B', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:54:45.378000', NULL, NULL, 'PKT_1775043675758', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775044798616', 'MPL_1774681038018', 'KLS_1774678349870', 'sarah001', 'Contoh perilaku dakwah yang mencerminkan keramahan islam di lingkungan sekolah adalah...', 'Mengejek teman yang berbeda agama', 'Membantu teman tanpa membedakan latar belakang', 'Mengabaikan teman yang kesulitan', 'Memaksakan pendapat saat diskusi', NULL, 'B', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-01T19:59:58.616000', NULL, NULL, 'PKT_1775043675758', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775046828790', 'MPL_1774681038018', 'KLS_1774678349870', 'sarah001', 'Seorang ketua organisasi harus mengambil keputusan dalam konflik antara dua anggota, salah satunya adalah teman dekatnya. Sikap yang mencerminkan perilaku jujur adalah...', 'Membela teman dekat agar hubungan tetap baik', 'Memghindari masalah dan tidak mengambil keputusan', 'Memutuskan berdasarkan fakta dan aturan yang berlaku', 'Mengikuti pendapat mayoritas tanpa mempertimbangkan kebenaran', NULL, 'C', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-01T20:33:48.790000', NULL, NULL, 'PKT_1775043675758', 'YA') ON CONFLICT (id) DO NOTHING;
