INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775100441874', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Proses metabolisme yang bertujuan memecah senyawa kompleks menjadi senyawa sederhana dan melepaskan energi disebut...', 'Anabolisme', 'Katabolisme', 'Fotosintesis', 'Sintesis protein', NULL, 'B', 'Katabolisme adalah penguraian molekul kompleks (gula, protein, lemak) menjadi sederhana (CO2, H2O) untuk melepaskan energi (ATP).', 'Sedang', 4, 'DISETUJUI', '2026-04-02T11:27:21.874000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775100583479', 'MPL_1774677098386', 'KLS_1774678349870', 'tuti001', 'Contoh proses katabolisme yang terjadi di dalam sel makhluk hidup adalah...', 'Fotosintesis', 'Respirasi seluler (aerob)', 'Sintesis lemak', 'Sintesis protein', NULL, 'B', 'Respirasi sel memecah glukosa dengan oksigen menjadi energi. Fotosintesis, sintesis lemak dan protein adalah anabolisme.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T11:29:43.479000', NULL, NULL, 'PKT_1775041451285', 'YA') ON CONFLICT (id) DO NOTHING;
