INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775108696128', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '2. Perilaku ujub sangat berbahaya karena . . . .', 'Membuat orang lain senang', 'Dapat menghapus pahala amal kebaikan', 'Meningkatkan kualitas diri', 'Mendapat teman banyak', NULL, 'B', 'Ujub merupakan penyakit hati (merasa diri lebih baik dari orang lain) yang sangat berbahaya karena dapat merusak amal ibadah dan menumbuhkan kesombongan pada diri.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T13:44:56.128000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775110688864', 'MPL_1774680933499', 'KLS_1774678349870', 'selfi001', '1. Tahap produksi secara umum terbagi atas pengolahan bahan atau pembahanan, pembentukan, perakitan dan....', 'Pemasaran', 'Pembentukan', 'Finishing', 'Produk', NULL, 'C', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-02T14:18:08.864000', NULL, NULL, 'PKT_1775110688078', 'YA') ON CONFLICT (id) DO NOTHING;
