INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775110977148', 'MPL_1774680933499', 'KLS_1774678349870', 'selfi001', '2. Yang tidak termasuk tahap produksi...', 'Pengemasan', 'Finishing', 'Pembahanan', 'Perakitan', NULL, 'A', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-02T14:22:57.148000', NULL, NULL, 'PKT_1775110688078', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775111412737', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '4. Sikap menerima dengan lapang dada atas segala ketentuan Allah SWT setelah berusaha secara maksimal disebut . . .', 'Tawakal', 'Qana''ah', 'Sabar', 'Syukur', NULL, 'B', 'Qana''ah merupakan sikap rela menerima dan merasa cukup atas pemberian Allah SWT, serta menjauhkan diri dari rasa tidak puas dan perasaan kurang.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T14:30:12.737000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
