INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775112544350', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '5. Seseorang yang memiliki sikap tawadhu akan senantiasa . . .', 'Merasa dirinya lebih mulia dari orang lain', 'Merendah hati dan tidak sombong', 'Memamerkan amal kebaikan', 'Mengharap pujian manusia', NULL, 'B', 'Tawadhu merupakan sikap rendah hati. dan orang yang memiliki sikap ini biasanya akan senantiasa merendahkan hatinya dan berlaku santun terhadap orang lain, sehingga tidak merasa bahwa dirinya lebih baik dari orang lain', 'Sedang', 4, 'DISETUJUI', '2026-04-02T14:49:04.350000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775113363056', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '6. Sikap Al-Amanah dalam kehidupan sehari-hari ditunjukkan dengan . . .', 'Memberi sedekah secara sembunyi', 'Berbicara lemah lembut', 'Bekerja keras untuk kekayaan', 'Menyampaikan titipan kepada yang berhak', NULL, 'D', 'Amanah berarti dapat dipercaya. Seseorang yang memiliki sikap amanah adalah sosok yang dapat dipercaya serta memiliki tanggung jawab pada setiap tugas maupun kepercayaan yang diberikan kepada dirinya.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T15:02:43.056000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775113880467', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '7. Sikap memamerkan amal ibadah kepada orang lain agar mendapatkan pujian disebut . . .', 'Sunnah', 'Riya', 'Hasad', 'Ujub', NULL, 'B', 'Riya berarti memperlihatkan atau memamerkan ibadah dengan tujuan agar dilihat oleh orang dan tidak berniat beribadah hanya karena Allah semata.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T15:11:20.467000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775114651598', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '8. Perilaku menyebarkan berita bohong untuk memecah belah persaudaraan disebut . . .', 'Ghibah', 'Fitnah', 'Hasad', 'Riya', NULL, 'B', 'Fitnah adalah perkataan bohong, tuduhan palsu atau berita tanpa dasar yang disebarkan dengan maksud menjelekkan, merusak reputasi atau merugikan kehormatan orang lain. Sehingga fitnah dapat memicu perpecahan baik dalam persaudaraan maupun orang lain.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T15:24:11.598000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775114851469', 'MPL_1774680933499', 'KLS_1774678349870', 'selfi001', '5. Yang termasuk salah satu kunci keberhasilan penjualan produk inovatif adalah...', 'Pendapatan orang', 'Pekerjaan orang', 'Harga jual', 'Biaya produksi', NULL, 'C', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-02T15:27:31.469000', NULL, NULL, 'PKT_1775110688078', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775115319689', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '9. Sikap syaja''ah (berani) dalam islam berlandaskan pada . . .', 'Kekuatan fisik dan otot', 'Kebenaran dan keridaan Allah SWT', 'Dukungan dari banyak orang', 'Keinginan untuk di puji', NULL, 'B', 'Syaja''ah merupakan keberanian yang berdasar pada kebenaran yang dilakukan dengan penuh pertimbangan untuk mengharapkan ridha Allah SWT.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T15:35:19.689000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775116338342', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '10. Berikut ini yang merupakan contoh sikap Al- ''Afwu adalah . . . .', 'Membalas kejahatan dengan kejahatan', 'Membiarkan orang lain berbuat zalim', 'Memaafkan kesalahan orang lain meskipun mampu membalas', 'Menghindar dari orang yang pernah bersalah', NULL, 'C', 'Al- ''Afwu berarti Pemaaf. Jadi, Sikap orang yang mengamalkan kandungan nilai yang terkandung dalam Asmaul Husna Al- ''Afwu adalah selalu berusaha memaafkan kesalahan orang lain.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T15:52:18.342000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775117051806', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '11. Dampak negatif dari sikap Hasad adalah . . . .', 'Menambah teman', 'Memakan kebaikan seperti api memakan kayu bakar', 'Hati menjadi tenang', 'Mendapat rezeki yang melimpah', NULL, 'B', 'Hasad merupakan penyakit iri hati atau dengki dan dapat berbahaya karena perasaan ingin merugikan orang lain karena keberhasilan atau kebahagiaan mereka. Sehingga dapat menghanguskan amal kebaikan laksana api yang membakar kayu.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T16:04:11.806000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775119754296', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '12. Sikap merasa diri lebih hebat, lebih pintar, atau lebih mulia dari pada orang lain disebut . . .', 'Riya', 'Ujub', 'Takabur', 'Hasad', NULL, 'C', 'Takabur atau sombong itu pada hakiatnya  merupakan suatu sikap dimana seseorang berusaha membesar-besarkan dirinya, karena merasa diri lebih dari orang lain.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T16:49:14.296000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775120434453', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '13. Perilaku menceritakan keburukan orang lain yang tidak ada pada dirinya disebut . . .', 'Ghibah', 'Fitnah', 'Hasad', 'Riya', NULL, 'B', 'Karena tindakan tersebut adalah tuduhan palsu dan bentuk pencemaran nama baik yang bertujuan merusak martabat seseorang.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T17:00:34.454000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775120618471', 'MPL_1774677158433', 'KLS_1774678349870', 'farah001', 'selesaikan soal dibawah ini dan pilih salah satu jawaban yang benar antara A, B, C atau D.', 'A', 'B', 'C', 'D', NULL, 'A', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-02T17:03:38.471000', NULL, 'https://drive.google.com/uc?export=view&id=1KU6elfTgIzgx5iYKPFL_QxeX1zksGiaF', 'PKT_1775051998896', 'TIDAK') ON CONFLICT (id) DO NOTHING;
