INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775121040623', 'MPL_1774677158433', 'KLS_1774678349870', 'farah001', 'Sebuah segitiga siku-siku memiliki panjang sisi tegak 3 cm dan sisi alas 4 cm. Panjang sisi miring segitiga tersebut adalah …', '5 cm', '6 cm', '7 cm', '8 cm', NULL, 'A', NULL, 'Mudah', 4, 'DISETUJUI', '2026-04-02T17:10:40.623000', NULL, NULL, 'PKT_1775051998896', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775121166681', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '14. Sikap tawakal yang benar adalah . . .', 'Berusaha maksimal lalu pasrah', 'Pasrah tanpa berbuat apa-apa', 'Mengandalkan orang lain', 'Yakin pasti berhasil tanpa usaha', NULL, 'A', 'Karena tawakal merupakan bentuk keseimbangan antara ikhtiar fisik (ketaan) dan peyerahan hati kepada Allah SWT (keimanan).', 'Sedang', 4, 'DISETUJUI', '2026-04-02T17:12:46.681000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775121325113', 'MPL_1774677158433', 'KLS_1774678349870', 'farah001', 'Sebuah tangga disandarkan pada dinding. Jarak kaki tangga ke dinding adalah 6 m, dan panjang tangga 10 m. Tinggi yang dicapai tangga pada dinding adalah …', '9 m', '8 m', '7m', '6 m', NULL, 'B', NULL, 'Mudah', 4, 'DISETUJUI', '2026-04-02T17:15:25.113000', NULL, NULL, 'PKT_1775051998896', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775121654766', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '15. Sikap mencintai kebersihan hati dan kejujuran diri sendiri dari perbuatan yang merendahkan martabat disebut . . .', 'Iffah', 'Qana''ah', 'Tawadhu', 'Sabar', NULL, 'A', 'Karena ''Iffah bermakna menahan diri dan menjaga kesucian diri dari perkara-perkara yang di haramkan, buruk, atau merusak harga diri.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T17:20:54.766000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775121888126', 'MPL_1774677158433', 'KLS_1774678349870', 'farah001', 'Suatu relasi dari himpunan A ke himpunan B disebut fungsi apabila …', 'setiap anggota A berpasangan dengan tepat satu anggota B', 'setiap anggota B berpasangan dengan tepat satu anggota A', 'setiap anggota A berpasangan dengan lebih dari satu anggota B', 'hanya sebagian anggota A yang berpasangan dengan anggota B', NULL, 'A', 'Fungsi adalah relasi yang memasangkan setiap anggota domain (A) dengan tepat satu anggota kodomain (B).', 'Mudah', 4, 'DISETUJUI', '2026-04-02T17:24:48.126000', NULL, NULL, 'PKT_1775051998896', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775121995847', 'MPL_1774677158433', 'KLS_1774678349870', 'farah001', 'Diketahui himpunan A = {1, 2, 3} dan B = {a, b}. Relasi berikut yang merupakan fungsi adalah …', '{(1, a), (2, b), (3, a)}', '{(1, a), (1, b), (2, a)}', '{(1, a), (2, b)}', '{(1, a), (2, b), (3, a), (3, b)}', NULL, 'A', 'A benar karena setiap anggota A memiliki tepat satu pasangan di B.
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775122291543', 'MPL_1774677158433', 'KLS_1774678349870', 'farah001', 'Hasil dari (3+2i)+(5−4i)  adalah …', '8+6i', '8−2i', '2−2i', '8+2i', NULL, 'B', NULL, 'Mudah', 4, 'DISETUJUI', '2026-04-02T17:31:31.543000', NULL, NULL, 'PKT_1775051998896', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775122587918', 'MPL_1774677158433', 'KLS_1774678349870', 'farah001', 'Hasil dari (2+3i)(1−i) adalah …', '-1+5', '5+1', '5+i', '5-i', NULL, 'C', NULL, 'Mudah', 4, 'DISETUJUI', '2026-04-02T17:36:27.918000', NULL, NULL, 'PKT_1775051998896', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775122758251', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '16. Perwujudan sikap syukur atas nikmat Allah tidak hanya di ucapkan, tetapi juga . . .', 'Di pamerkan kepada orang lain', 'Mengeluh atas kekurangan', 'Menggunakan nikamat untuk ketaan', 'Merasa nikmat itu hasil nikmat sendiri', NULL, 'C', 'Karena syukur dalam islam merupakan konsep menyeluruh yang melibatkan hati, lisan, dan anggota badan. Syukur adalah tindakan memanfaatkan nikmat, Syukur yang hakiki ialah menggunakan nikmat sesuai tujuan  yang di anugerahkan dengan senantiasa mendekatkan diri kepada Allah SWT.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T17:39:18.251000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775123072845', 'MPL_1774677158433', 'KLS_1774678349870', 'farah001', 'budi menyandarkan tangga yang panjangnya 5m, pada sebatang pohon, jarakujung bawah tangga terhadap pangkal pohon 3m, berapa meter tinggi ujung atas tangga dari tanah ?', '16', '4', '-16', '-4', NULL, 'B', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-02T17:44:32.845000', NULL, NULL, 'PKT_1775051998896', 'TIDAK') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775123538574', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '17. Bahaya dari perilaku Namimah adalah . . . .', 'Mempererat silaturahmi', 'Mendatangkan ketenangan', 'Menimbulkan perpecahan dan permusuhan', 'Meningkatkan derajat', NULL, 'C', 'Namimah (adu domba) sangat berbahaya karena secara sengaja menyebarkan informasi rahasi atau fitnah yang bertujuan merusak hubungan, menciptakan rasa saling curiga dan memprovokasi konflik antara indifidu atau kelompok. Perilaku ini akan memicu permusuhan, memutus tali persaudaraan, dan merusak keharmonisan sosial.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T17:52:18.574000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775123976661', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '18. Seseorang yang berjanji lalu mengingkarinya merupakan ciri-ciri . . .', 'Musyrik', 'Munafik', 'Kafir', 'Murtad', NULL, 'B', 'Karena perilaku tersebut mencerminkan ketidaksesuaian antara perkataan dan perbuatan, yang merupakan inti dari kemunafikan.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T17:59:36.662000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775124644402', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '19. Sikap arif dalam menyelesaikan masalah ditunjukkan dengan . . .', 'Mengunakan kekerasan', 'Mengambil keputusan secara emosional', 'Bertindak bijaksana dan mempertimbangkan kemaslahatan', 'Membiarkan masalah terselesaikan sendiri', NULL, 'C', 'Karena hal tersebut merupakan inti dari hikmah dan kepemimpinan yang bertanggung jawab. Seseorang yang arif mampu menggunakan akal, pengalaman, dan pengetahuannya untuk menempatkan segala sesuatu sesuai pada tempatnya.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T18:10:44.402000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775125447059', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '20. Orang yang qana''ah akan terhindar dari penyakit hati . . . .', 'Riya', 'Hasad', 'Tamak', 'Takabur', NULL, 'C', 'Orang yang memiliki sifat qana ''ah (merasa cukup) akan terhindar dari penyakit hati tamak (serakah). Karena Qana''ah berfungsi sebagai benteng batin yang mengendalikan nafsu duniawi.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T18:24:07.059000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775126113692', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '21. Salah satu keutamaan sikap ikhlas adalah . . . .', 'Mendapat pujian manusia', 'Amalnya di terima oleh Allah SWT', 'Terkenal  di kalangan masyarakat', 'Hati menjadi gelisah', NULL, 'B', 'Ikhlas menjadikan amal diterima Allah SWT. Karena keikhlasan adalah inti dan syarat mutlak ibadah, memastikan niat murni hanya mengharap ridha-Nya dan bukan pujian manusia. Amal yang ikhlas di nilai berdasarkan ketulusan hati, bukan jumlahnya, sehingga berpotensi besar pahalanya dan terhindar dari sifat riya atau sombong.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T18:35:13.692000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775126655622', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '22. Sikap ijtihad dalam kehidupan bermasyarakat berarti . . . .', 'Memisahkan diri', 'Bersatu padu', 'Bersaing sehat', 'Berserah diri', NULL, 'B', 'Sikap ijtihad dalam kehidupan bermasyarakat berarti bersatu padu. Karena ijtihad menuntut kolaborasi, penyatuan pandangan dan kerjasama antara sesama masyarakat untuk memecahkan masalah.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T18:44:15.622000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775129067156', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '23. Contoh sikap amanah terhadap diri sendiri adalah . . . .', 'Menjaga kesehatan jasmani dan rohani', 'Mengembalikan barang teman', 'Belajar hanya saat ujian', 'Tidur sepanjang hari', NULL, 'A', 'Menjaga kesehatan jasmani dan rohani di anggap sebagai contoh utama sikap amanah terhadap diri sendiri karena tubuh dan iwa manusia bukanlah milik mutlak, melainkan titipan (amanah ) dari Sang Pencipta. Sebagai pemegang titipan, manusia bertanggung jawab penuh untuk merawat, menjaga, dan menggunakannya dengan baik, bukan merusaknya.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T19:24:27.156000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775130028909', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '24. Contoh perilaku takabur adalah . . . .', 'Menolak kebenaran dan meremehkan orang lain', 'Berjalan dengan santai', 'Berbicara dengan suara pelan', 'Menghargai pendapat', NULL, 'A', 'Menolak kebenaran dan meremehka orang lain adalah bentuk takabur (sombong ) karena keduanya berakar dari perasaan diri lebih mulia,  sempurna atau hebat dibandingkan orang lain.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T19:40:28.909000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775130853222', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', 'Kebalikan dari sifat dinamis adalah  . . . .', 'Progresif ', 'Inovatif', 'Statis', 'Kreatif', NULL, 'C', 'Karena keduanya menggambarkan dua kondisi yang bertolak belakang. Dinamis berarti bergerak, berubah-ubah, dan berkembang. Sementara statis berarti diam, tetap atau tidak berubah.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T19:54:13.222000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775131242215', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '26. Sikap terpuji yang sangat di anjurkan saat mendapat musibah adalah . . . .', 'Marah-marah', 'Meratapi nasib', 'Sabar dan ikhlas', 'Berputus asa', NULL, 'C', 'Sikap sabar dan ikhlas merupakan kunci ketenangan batin, bentuk tertinggi dari keimanan, serta jalan untuk mendapatkan pahala tanpa batas dan ampunan dari Allah SWT.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T20:00:42.215000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775131779964', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '27. Sikap serakah dan tidak pernah puas dengan apa yang dimiliki menyebabkan seseorang . . . .', 'Qana''ah', 'Bersyukur', 'Jauh dari rasa cukup', 'Tawadhu', NULL, 'C', 'Karena hal ini memicu kecemasan, mengabaikan apa yang sudah dimiliki, dan mengikis kemampuan untuk bersyukur. Akibatnya, fokus beralih dari nikmat hidup menjadi pengejaran materi yang tak berujung.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T20:09:39.964000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775132756150', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '28. Perilaku ghibah dilarang karena dapat . . . .', 'Menambah wawasan', 'Merusak nama baik orang lain', 'Memperbaiki diri', 'Meningkatkan percaya diri', NULL, 'B', 'Gibah didefinisikan sebagai membicarakan keburukan atau aib seseorang di belakangnya, yang mana jika orang tersebut mendengarnya, ia akan merasa tidak suka.  Sehingga dampaknya  dapat merusak nama baik orang yang di bicarakan.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T20:25:56.150000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775133603741', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '29. Cara menghindari sikap riya adalah . . . .', 'Ikhlas dalam beramal', 'Selalu beramal di depan umum', 'Menceritakan amal kebaikan', 'Beramal hanya saat di lihat guru', NULL, 'A', 'Ikhlas berarti memurnikan niat hanya untuk Allah, sehingga menjalankan tujuan mendpatkan pujian manusia (riya).', 'Sedang', 4, 'DISETUJUI', '2026-04-02T20:40:03.741000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775134571392', 'MPL_1774677203314', 'KLS_1774678349870', 'asrida001', 'Perkembangan teknologi digital membawa perubahan besar dalam dunia pendidikan siswa kini dapat mengakses berbagai sumber belajar secarah daring dengan mudah, namun kemudahan ini juga menuntut kemampuan membaca cepat agar informasi yang banyak dapat di pahami dalam waktu singkat 
