INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1775136296593', 'MPL_1774680873966', 'KLS_1774678349870', 'sahidah001', '30. Contoh perilaku kerja keras yang sesuai dengan ajaran islam adalah . . . .', 'Bekerja terus menerus hingga melupakan shalat', 'Bekerja keras hanya saat di awasi pimpinan', 'Belajar sungguh-sungguh untuk meraih cita-cita', 'Menghalalkan segala cara untuk hasil maksimal', NULL, 'C', 'Karena hal tersebut merupakan bentuk ikhtiar (usaha) maksimal yang bernilai ibadah menuntut tanggung jawab serta menunjukkan rasa syukur atas nikmat akal dan waktu.', 'Sedang', 4, 'DISETUJUI', '2026-04-02T21:24:56.593000', NULL, NULL, 'PKT_1775107911820', 'YA') ON CONFLICT (id) DO NOTHING;
