INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776258585974', 'MPL_1774677178843', 'KLS_1774688141018', 'aco001', 'Ketika membaca Al-Qur’an di rumah, seorang siswa melewati ayat sajdah tetapi tidak melakukan sujud. Hukum meninggalkan sujud tersebut adalah …', 'Berdosa besar', 'Berdosa kecil', 'Tidak berdosa karena hukumnya sunnah', 'Wajib mengganti dengan shalat', NULL, 'C', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-15T21:09:45.974000', NULL, NULL, 'PKT_1776258250800', 'YA') ON CONFLICT (id) DO NOTHING;
