INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776259053086', 'MPL_1774677178843', 'KLS_1774688141018', 'aco001', 'Setelah mendengar kabar bahwa ia lulus ujian, Ali langsung sujud sebagai bentuk ucapan terimakasih kepada Allah. Sujud tersebut disebut …', 'Sujud Sahwi', 'Sujud Syukur', 'Sujud Tilawah', 'Sujud Wajib', NULL, 'B', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-15T21:17:33.086000', NULL, NULL, 'PKT_1776258250800', 'YA') ON CONFLICT (id) DO NOTHING;
