INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776858195941', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Hukum bacaan yang terjadi apabila ada wawu sukun atau ya sukun yang didahului huruf berharkat fathah dan berada di akhir ayat (waqaf) disebut..', 'Mad Layyin', 'Mad Tamkin', 'Mad Silah', 'Mad Badal', NULL, 'A', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-22T19:43:15.941000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776858509553', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Di bawah ini yang merupakan contoh bacaan Mad Silah Qashirah adalah...', 'لَهُ مَا فِي السَّمَاوَاتِ', 'بِأَيْدِي سَفَرَةٍ', 'ءَامَنُوا', 'وَالضُّحَى', NULL, 'A', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-22T19:48:29.553000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776858565299', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Hukum bacaan Mad Farqi berfungsi untuk membedakan antara kalimat tanya dengan kalimat berita. Manakah di bawah ini yang merupakan contoh Mad Farqi?', 'الئن', 'ءآلذكرين', 'الحآقة', 'يس', NULL, 'B', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-22T19:49:25.299000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776858636695', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Dalam ilmu tajwid, bacaan Imalah (mencondongkan bunyi fathah ke arah kasrah) menurut riwayat Imam Hafs hanya terdapat pada satu tempat di dalam Al-Qur''an, yaitu pada kata...', 'مَجْرٰىهَا (QS. Hud: 41)', 'أَأَعْجَمِيٌّ (QS. Fussilat: 44)', 'بِئْسَ الِاسْمُ (QS. Al-Hujurat: 11)', 'لَا تَأْمَنَّا (QS. Yusuf: 11)', NULL, 'A', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-22T19:50:36.695000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776858696027', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Cara membaca kata لَا تَأْمَنَّا dalam QS. Yusuf ayat 11 dengan cara memonyongkan bibir untuk mengisyaratkan bunyi dhammah tanpa suara disebut bacaan...', 'Tashil', 'Naql', 'Isymam', 'Mad', NULL, 'C', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-22T19:51:36.027000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776858735057', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Memindahkan harkat hamzah ke huruf mati sebelumnya, seperti pada bacaan بِئْسَ الِاسْمُ (menjadi bi’salismu), disebut hukum bacaan...', 'Tashil', 'Naql', 'Mad Farqi', 'Imalah', NULL, 'B', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-22T19:52:15.057000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
