INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776934502501', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Perhatikan fenomena pergantian siang dan malam serta keteraturan alam semesta. Berdasarkan hadis tentang kekuasaan dan rahmat Allah Swt., hikmah utama yang dapat disimpulkan oleh seorang mukmin adalah..', 'Manusia memiliki kekuatan untuk mengendalikan alam', 'Allah Swt. Maha Kuasa namun kasih sayang-Nya mendahului murka-Nya', 'Rahmat Allah hanya diberikan kepada orang yang tidak pernah berdosa', 'Kekuasaan Allah terbatas hanya pada penciptaan langit saja', NULL, 'B', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-23T16:55:02.501000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776934545790', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Ketika seseorang menyadari betapa besarnya rahmat Allah Swt. yang telah mengampuni dosa-dosa hamba-Nya, maka sikap yang paling tepat untuk ditunjukkan adalah...', 'Merasa aman dan terus menerus melakukan kemaksiatan', 'Menjauhi pergaulan karena takut terkena dosa kembali', 'Selalu optimis dalam beribadah dan tidak berputus asa dari ampunan-Nya', 'Merasa diri paling suci dibandingkan orang lain', NULL, 'C', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-23T16:55:45.790000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776934587993', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Dalam sebuah hadis disebutkan bahwa "Tangan di atas lebih baik daripada tangan di bawah". Analisis yang tepat terhadap kandungan hadis tersebut dalam kehidupan sosial adalah...', 'Memberi lebih mulia daripada menerima bantuan', 'Orang miskin tidak perlu berusaha karena akan dibantu orang kaya', 'Mencari harta sebanyak-banyaknya untuk pamer kekuatan', 'Menghindari pemberian agar harta tidak berkurang', NULL, 'A', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-23T16:56:27.993000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776934655114', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Fatimah memiliki kelebihan makanan di rumahnya, sementara tetangganya sedang kelaparan. Sikap yang mencerminkan upaya menjauhi sifat kikir (bakhil) adalah..', 'Menyimpan makanan tersebut untuk cadangan bulan depan', 'Memberikan makanan kepada tetangga dengan perasaan terpaksa', 'Segera membagikan makanan tersebut dengan ikhlas tanpa rasa takut kekurangan', 'Menjual makanan tersebut kepada tetangganya dengan harga murah', NULL, 'C', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-23T16:57:35.114000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776934846846', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Hadis tentang optimis dan sabar mengajarkan bahwa setiap ketetapan Allah memiliki hikmah. Dalam menghadapi fenomena kegagalan dalam ujian, analisis perilaku yang benar adalah...', 'Menangis meratapi nasib selama berhari-hari', 'Menilai kegagalan sebagai akhir dari segalanya', 'Bersabar atas hasil yang diterima dan tetap optimis mencoba kembali', 'Berhenti belajar karena merasa tidak memiliki bakat', NULL, 'C', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-23T17:00:46.846000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776934902700', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', '"Tidaklah harta itu berkurang karena sedekah." Makna analisis dari penggalan hadis tentang infak tersebut adalah...', 'Jumlah nominal uang di dompet akan tetap secara ajaib', 'Allah akan memberikan keberkahan dan ganti yang lebih baik bagi orang yang berinfak', 'Berinfak hanya dilakukan saat kita memiliki harta yang melimpah (kaya raya)', 'Infak tidak wajib dilakukan jika kita masih memiliki hutang piutang', NULL, 'B', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-23T17:01:42.700000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776935060356', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Banyaknya sampah yang menyumbat saluran air seringkali menyebabkan banjir. Jika dikaitkan dengan hadis tentang kepedulian lingkungan, tindakan yang merupakan bentuk iman adalah...', 'Menunggu pemerintah datang membersihkan sampah', 'Menyingkirkan gangguan (sampah) dari jalan atau saluran air', 'Membiarkan sampah tersebut selama tidak mengganggu rumah sendiri', 'Mengimbau orang lain bekerja sementara kita hanya melihat saja', NULL, 'B', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-23T17:04:20.356000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776935211525', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Hadis yang menyatakan "Dunia adalah ladang bagi akhirat" mengandung pengertian bahwa...', 'Kehidupan dunia tidak penting dan harus ditinggalkan', 'Segala amal baik di dunia akan dipanen hasilnya di akhirat kelak', 'Kita boleh mengejar dunia tanpa memikirkan ibadah', 'Sukses di akhirat bisa didapat tanpa bekerja keras di dunia', NULL, 'B', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-23T17:06:51.528000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776935281024', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Sebagai siswa kelas 9 yang memahami keseimbangan dunia dan akhirat, sikap yang benar dalam menghadapi ujian sekolah adalah...', 'Hanya berdoa terus menerus di masjid tanpa belajar', 'Belajar dengan giat tanpa pernah menjalankan salat', 'Berusaha maksimal dalam belajar dan tetap istikamah menjalankan ibadah', 'Mencontek agar nilai bagus sehingga bisa membanggakan orang tua', NULL, 'C', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-23T17:08:01.024000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776935326538', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Kejujuran dalam bermuamalah (berdagang/bertransaksi) sangat ditekankan dalam hadis. Analisis dampak jika seorang pedagang berlaku jujur adalah...', 'Dagangannya akan sepi karena harganya terlalu transparan', 'Mendapatkan kepercayaan pelanggan dan keberkahan dari Allah Swt.', 'Sulit mendapatkan keuntungan yang besar dalam waktu singkat', 'Sering ditipu oleh pembeli yang ingin mencari harga murah', NULL, 'B', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-23T17:08:46.538000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1776935373643', 'MPL_1774681038018', 'KLS_1774688141018', 'sarah001', 'Hadis menyebutkan bahwa "Menuntut ilmu adalah kewajiban bagi setiap muslim". Analisis yang tepat mengenai keutamaan menuntut ilmu adalah...', 'Ilmu hanya wajib bagi orang yang ingin menjadi guru atau dosen', 'Dengan ilmu, jalan seseorang menuju surga akan dimudahkan oleh Allah Swt.', 'Ilmu pengetahuan umum lebih penting daripada ilmu agama', 'Menuntut ilmu cukup dilakukan sampai lulus madrasah saja', NULL, 'B', NULL, 'Sedang', 4, 'DISETUJUI', '2026-04-23T17:09:33.643000', NULL, NULL, 'PKT_1776855260857', 'YA') ON CONFLICT (id) DO NOTHING;
