INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1780062484733', 'MPL_1775772077386', 'KLS_1774688089286', 'hijrah001', 'Nabi Muhammad SAW lahir pada Tahun Gajah. Mengapa tahun kelahiran beliau dinamakan demikian?', 'Karena adanya hadiah puluhan ekor gajah dari raja Ethiopia kepada masyarakat suku Quraisy', 'Karena masyarakat Arab pada tahun tersebut memulai perdagangan luar negeri menggunakan gajah', 'Karena jumlah hewan gajah di kota Mekkah mengalami lonjakan yang sangat pesat pada tahun itu', 'Karena bertepatan dengan penyerangan kota Mekkah oleh pasukan bergajah yang dipimpin Abrahah', NULL, 'D', NULL, 'Sedang', 4, 'DISETUJUI', '2026-05-29T21:48:05.033000', NULL, NULL, 'PKT_1780062484344', 'YA') ON CONFLICT (id) DO NOTHING;
