INSERT INTO soal (id, mapel_id, kelas_id, guru_id, teks, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci, pembahasan, tingkat, jumlah_opsi, status, tanggal, catatan, gambar_url, paket_id, acak) VALUES ('SL_1780062775358', 'MPL_1774681038018', 'KLS_1774688089286', 'sarah001', 'Tujuan Mempelajari Ilmu Tajwid Adalah ...', 'Menghafal Semua Surat Al-Qur''an', 'Menulis Ayat Al-Qur''an', 'Membaca Al-Qur''an dengan Benar dan baik', 'Mengetahui Arti Seluruh Ayat Al-Qur''an', NULL, 'C', NULL, 'Sedang', 4, 'DRAFT', '2026-05-29T21:52:55.784000', NULL, NULL, 'PKT_1780062473236', 'YA') ON CONFLICT (id) DO NOTHING;
